let raw =
  $json.text ||
  $json.t ||
  $json.output?.[0]?.content?.[0]?.text ||
  "";

raw = String(raw).trim();

// If it starts with text:{...}
raw = raw.replace(/^text:/, "").trim();

// Remove markdown
raw = raw.replace(/```json/g, "").replace(/```/g, "").trim();

// Grab only the JSON object
const match = raw.match(/\{[\s\S]*\}/);

if (!match) {
  return [{
    json: {
      parse_error: true,
      raw_response: raw
    }
  }];
}

const parsed = JSON.parse(match[0]);

return [{
  json: {
    invitee_email: parsed.invitee_email || "",
    event_date: parsed.event_date || "",
    event_time: parsed.event_time || ""
  }
}];

const eventDate = $json.event_date;
const eventTime = $json.event_time;

if (!eventDate || !eventTime) {
  return [{
    json: {
      error: "Missing event_date or event_time",
      received: $json
    }
  }];
}

function convertTo24Hour(timeValue) {
  const clean = String(timeValue)
    .trim()
    .replace(/\s+/g, " ")
    .toUpperCase();

  const match = clean.match(/^(\d{1,2}):(\d{2})\s*(AM|PM)$/);

  if (!match) {
    return null;
  }

  let hours = Number(match[1]);
  const minutes = match[2];
  const period = match[3];

  if (period === "PM" && hours !== 12) hours += 12;
  if (period === "AM" && hours === 12) hours = 0;

  return `${String(hours).padStart(2, "0")}:${minutes}`;
}

const time24 = convertTo24Hour(eventTime);

if (!time24) {
  return [{
    json: {
      error: "Invalid time format",
      event_time_received: eventTime,
      full_input: $json
    }
  }];
}

const meetingDateTime = new Date(`${eventDate}T${time24}:00-04:00`);

if (isNaN(meetingDateTime.getTime())) {
  return [{
    json: {
      error: "Invalid date/time",
      eventDate,
      eventTime,
      time24
    }
  }];
}

meetingDateTime.setMinutes(meetingDateTime.getMinutes() - 30);

return [{
  json: {
    ...$json,
    event_time_24h: time24,
    send_at: meetingDateTime.toISOString()
  }
}];

const incomingAddress = $('Find CRM Lead by Email').first().json.property_managed_property; // CHANGE THIS ONLY

function normalize(address) {
  return String(address || "")
    .toLowerCase()
    .replace(/\./g, "")
    .replace(/,/g, "")
    .replace(/#/g, "")
    .replace(/\bavenue\b/g, "ave")
    .replace(/\bstreet\b/g, "st")
    .replace(/\broad\b/g, "rd")
    .replace(/\bdrive\b/g, "dr")
    .replace(/\bboulevard\b/g, "blvd")
    .replace(/\bplace\b/g, "pl")
    .replace(/\bcourt\b/g, "ct")
    .replace(/\bunit\b/g, "")
    .replace(/\bsuite\b/g, "")
    .replace(/\bapt\b/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function addressKey(address) {
  const cleaned = normalize(address);

  const match = cleaned.match(/(\d+)\s+([a-z]+)/);

  return match ? `${match[1]} ${match[2]}` : cleaned;
}

const incomingKey = addressKey(incomingAddress);

const matches = $input.all().filter(item => {
  const sheetAddress = item.json.address;
  const sheetKey = addressKey(sheetAddress);

  return sheetKey === incomingKey;
});

const strIds = matches
  .map(item => item.json.col_1)
  .filter(value => String(value || "").startsWith("STR-"));

return [
  {
    json: {
      incomingAddress,
      incomingKey,
      isSTR: matches.length > 0,
      matchCount: matches.length,
      strIds,
      matches: matches.map(item => item.json)
    }
  }
];

const emails = $input.all();

const messages = emails.map(item => item.json);

const incomingFromThem = messages.filter(m => {
  const from = String(m.from || "").toLowerCase();
  const leadEmail = String($('Find CRM Lead by Email').first().json.property_email || $('Find CRM Lead by Email').first().json.email || "").toLowerCase();

  return from.includes(leadEmail);
});

return [{
  json: {
    hasEmailHistory: messages.length > 0,
    totalEmailsFound: messages.length,
    hasRepliedOrEmailedUs: incomingFromThem.length > 0,
    emailsFromThemCount: incomingFromThem.length,
    emailsToOrFromThem: messages
  }
}];
